const body = $input.first().json.body || $input.first().json;
const db06_id = (body.db06_id || body.id || '').toString().replace(/-/g, '');
if (!db06_id) throw new Error('missing db06_id');
return [{ json: { db06_id } }];

const p = $input.first().json;
const TARGET_RELS = ["對應提案", "對應管考", "對應項目", "對應協作", "對應內容", "對應庫存", "對應對象", "對應標籤", "對應地點", "對應提供對象"];
let target_id = '', target_rel = '';
for (const rel of TARGET_RELS) {
  const arr = p.properties[rel]?.relation || [];
  if (arr.length) { target_id = (arr[0].id||'').replace(/-/g,''); target_rel = rel; break; }
}
return [{ json: {
  db06_id: p.id.replace(/-/g, ''),
  ai_mode: p.properties['ai模式']?.select?.name || '',
  execute_idea_db06: p.properties['執行構想']?.rich_text?.map(t=>t.plain_text).join('') || '',
  mingxi_content: p.properties['明細內容']?.rich_text?.map(t=>t.plain_text).join('') || '',
  db05_id: target_id,
  target_rel: target_rel,
  mingxi_name: p.properties['明細名稱']?.title?.map(t=>t.plain_text).join('') || '',
  sort_num: p.properties['排序']?.number
}}];

const resp = $input.first().json;
const text = resp.content?.[0]?.text || '';
const usage = resp.usage || {};
let parsed;
try {
  const m = text.match(/\{[\s\S]*\}/);
  parsed = m ? JSON.parse(m[0]) : { execution_summary: text, target_updates: {}, needs_human_intervention: true };
} catch (e) {
  parsed = { execution_summary: 'JSON parse failed: ' + text.slice(0, 500), target_updates: {}, needs_human_intervention: true };
}
const prompt = $("Build Claude prompt").first().json;
const ai_mode = prompt.ai_mode || '';
const tu = parsed.target_updates || {};
const tu_keys = Object.keys(tu);
const sanitize = s => (s || '').toString()
  .replace(/[\/\\:<>#@\[\]\{\}\|\^\`\*_~"']/g, ' ')
  .replace(/[\u2010-\u2027\u2030-\u205E]/g, ' ')
  .replace(/[\uFF00-\uFF0F\uFF1A-\uFF20\uFF3B-\uFF40\uFF5B-\uFF65]/g, ' ')
  .replace(/[\u3000-\u3017\u301D-\u303F]/g, ' ')
  .replace(/\s+/g, ' ').trim().slice(0, 600);
const cache_read = parseInt(usage.cache_read_input_tokens || 0);
const cache_write = parseInt(usage.cache_creation_input_tokens || 0);
const input_tokens = parseInt(usage.input_tokens || 0);
const output_tokens = parseInt(usage.output_tokens || 0);
const cost_usd = (input_tokens*3 + output_tokens*15 + cache_write*3.75 + cache_read*0.30)/1000000;
const cost_ntd = (cost_usd*32).toFixed(2);
const usage_line = '進=' + input_tokens + ' 出=' + output_tokens + ' cache讀=' + cache_read + ' cache寫=' + cache_write + ' 成本NT' + cost_ntd;
const is_planner = ai_mode.includes('企劃') || ai_mode.includes('構想');
const tag_src = Array.isArray(parsed['對應標籤候選']) ? parsed['對應標籤候選'] : (Array.isArray(tu['對應標籤候選']) ? tu['對應標籤候選'] : []);
const tag_candidates = is_planner ? tag_src.slice(0, 8) : [];
const tag_note = tag_candidates.length > 0 ? (' | 對應標籤候選: ' + tag_candidates.map(t=>sanitize(t)).join('、')) : '';
const preview_text = tu_keys.length === 0 ? '無寫入' : ('寫入 ' + tu_keys.length + ' 欄位 (' + tu_keys.map(k=>sanitize(k)).join('、') + ')');
let validator_warning = '';
if (ai_mode.includes('文案') && tu.page_content) {
  const wc = (tu.page_content.toString().match(/^##\s+/gm) || []).length;
  const pc = prompt.planned_chapters || 0;
  if (pc > 0 && Math.abs(wc - pc) > 1) validator_warning = ' 警告 段落 ' + wc + ' 章 企劃 ' + pc + ' 章';
}
return [{ json: { ...parsed, ai_mode, db06_id: prompt.db06_id, db05_id: prompt.db05_id, mingxi_name: prompt.mingxi_name, sort_num: prompt.sort_num, usage_line, cost_ntd, input_tokens, output_tokens, cache_read, cache_write, tag_candidates, tag_note, preview_text, validator_warning, safe_summary: sanitize(parsed.execution_summary || '') } }];

const item = $("Parse Claude").first().json;
const ai_mode = item.ai_mode || '';
const tu = item.target_updates || {};
let target_props = {};
let target_children = [];
if (ai_mode.includes('企劃') || ai_mode.includes('構想')) {
  if (tu['主題名稱']) target_props['主題名稱'] = { rich_text: [{ text: { content: tu['主題名稱'].toString().slice(0, 200) } }] };
  if (tu['簡介摘要']) target_props['簡介摘要'] = { rich_text: [{ text: { content: tu['簡介摘要'].toString().slice(0, 2000) } }] };
  if (tu['執行構想']) target_props['執行構想'] = { rich_text: [{ text: { content: tu['執行構想'].toString().slice(0, 2000) } }] };
}
if (ai_mode.includes('文案') && tu['page_content']) {
  const paragraphs = tu['page_content'].toString().split(/\n\n+/).filter(p => p.trim());
  target_children = paragraphs.slice(0, 100).map(p => ({
    object: 'block', type: 'paragraph',
    paragraph: { rich_text: [{ text: { content: p.slice(0, 2000) } }] }
  }));
}
return [{ json: {
  ...item, target_props, target_children,
  has_keywords: false,
  summary: (item.execution_summary || '').toString().slice(0, 2000)
}}];

